import 'package:shared_preferences/shared_preferences.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';

class PresetStore {
  final SharedPreferences _prefs;

  PresetStore._(this._prefs);

  static Future<PresetStore> create() async {
    final prefs = await SharedPreferences.getInstance();
    return PresetStore._(prefs);
  }

  Future<List<FractalPreset>> loadUserPresets(String moduleId) async {
    final payload = _prefs.getString(_key(moduleId));
    return FractalPreset.listFromPrefs(payload);
  }

  Future<void> saveUserPreset(FractalPreset preset) async {
    final presets = await loadUserPresets(preset.moduleId);
    // Check for duplicate ID and replace if exists
    final existingIndex = presets.indexWhere((p) => p.id == preset.id);
    final List<FractalPreset> updated;
    if (existingIndex >= 0) {
      // Replace existing preset with same ID
      updated = [...presets];
      updated[existingIndex] = preset;
    } else {
      // Add new preset
      updated = [...presets, preset];
    }
    await _prefs.setString(_key(preset.moduleId), FractalPreset.listToPrefs(updated));
  }

  Future<void> deleteUserPreset(String moduleId, String presetId) async {
    final presets = await loadUserPresets(moduleId);
    final updated = presets.where((preset) => preset.id != presetId).toList();
    await _prefs.setString(_key(moduleId), FractalPreset.listToPrefs(updated));
  }

  Future<void> updatePreset(String moduleId, String presetId, {required String name}) async {
    final presets = await loadUserPresets(moduleId);
    final index = presets.indexWhere((p) => p.id == presetId);
    if (index < 0) return;
    final updated = [...presets];
    updated[index] = presets[index].copyWith(name: name);
    await _prefs.setString(_key(moduleId), FractalPreset.listToPrefs(updated));
  }

  String _key(String moduleId) => 'user_presets_$moduleId';
}

import 'dart:convert';

import 'package:flutter/foundation.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:flutter_fractals/core/models/fractal_palette.dart';

class PaletteStore {
  static const _key = 'user_palettes_v1';

  final SharedPreferences _prefs;

  PaletteStore._(this._prefs);

  static Future<PaletteStore> create() async {
    final prefs = await SharedPreferences.getInstance();
    return PaletteStore._(prefs);
  }

  List<FractalPalette> loadPalettes() {
    final list = _prefs.getStringList(_key);
    if (list != null) return _decodePaletteStringList(list);

    return _decodeLegacyPaletteArray(_prefs.getString(_key));
  }

  List<FractalPalette> _decodePaletteStringList(List<String> encodedPalettes) {
    final palettes = <FractalPalette>[];
    for (final encoded in encodedPalettes) {
      final palette = _tryDecodePaletteString(encoded);
      if (palette != null && palette.id.isNotEmpty) palettes.add(palette);
    }
    return palettes;
  }

  FractalPalette? _tryDecodePaletteString(String encoded) {
    try {
      return FractalPalette.fromJsonString(encoded);
    } catch (e) {
      if (kDebugMode) debugPrint('[FF] skipping palette entry: $e');
      return null;
    }
  }

  List<FractalPalette> _decodeLegacyPaletteArray(String? payload) {
    if (payload == null || payload.trim().isEmpty) return const [];

    try {
      final decodedArr = (jsonDecode(payload) as List).cast<Map>();
      return decodedArr
          .map((m) => FractalPalette.fromJson(m.cast<String, Object?>()))
          .where((p) => p.id.isNotEmpty)
          .toList();
    } catch (e) {
      if (kDebugMode) debugPrint('[FF] silent catch: $e');
      return const [];
    }
  }

  Future<void> savePalettes(List<FractalPalette> palettes) async {
    final list = palettes.map((p) => p.toJsonString(pretty: false)).toList();
    await _prefs.setStringList(_key, list);
  }
}

import 'dart:convert';
import 'package:flutter/foundation.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';

/// Persists exploration history and favorites to local storage.
///
/// History entries are stored in SharedPreferences as JSON.
/// Maintains separate storage for:
/// - Navigation history (limited size, auto-trimmed)
/// - Favorites (unlimited, user-managed)
///
/// {@category Services}
class HistoryStore {
  final SharedPreferences _prefs;

  static const String _historyKey = 'exploration_history';
  static const String _favoritesKey = 'exploration_favorites';
  static const int maxHistoryEntries = 100;
  static const int maxFavoriteEntries = 500;

  HistoryStore._(this._prefs);

  /// Creates a new [HistoryStore] instance.
  static Future<HistoryStore> create() async {
    final prefs = await SharedPreferences.getInstance();
    return HistoryStore._(prefs);
  }

  /// Loads the navigation history.
  ///
  /// Returns entries in chronological order (oldest first).
  List<HistoryEntry> loadHistory() => _loadEntries(_historySlot);

  /// Saves the navigation history.
  ///
  /// Automatically trims to [maxHistoryEntries].
  Future<void> saveHistory(List<HistoryEntry> entries) async {
    await _saveEntries(_historySlot, entries);
  }

  /// Loads the user's favorite locations.
  List<HistoryEntry> loadFavorites() => _loadEntries(_favoritesSlot);

  /// Saves the user's favorite locations.
  ///
  /// Capped at [maxFavoriteEntries] to prevent unbounded storage growth.
  Future<void> saveFavorites(List<HistoryEntry> favorites) async {
    await _saveEntries(_favoritesSlot, favorites);
  }

  /// Adds an entry to favorites.
  Future<void> addFavorite(HistoryEntry entry) async {
    final favorites = loadFavorites();
    // Check if already exists by ID
    if (favorites.any((f) => f.id == entry.id)) return;
    favorites.add(entry);
    await saveFavorites(favorites);
  }

  /// Removes an entry from favorites by ID.
  Future<void> removeFavorite(String entryId) async {
    final favorites = loadFavorites();
    final updated = favorites.where((f) => f.id != entryId).toList();
    await saveFavorites(updated);
  }

  /// Clears all navigation history.
  Future<void> clearHistory() async {
    await _prefs.remove(_historyKey);
  }

  /// Clears all favorites.
  Future<void> clearFavorites() async {
    await _prefs.remove(_favoritesKey);
  }

  List<HistoryEntry> _loadEntries(_HistoryStoreSlot slot) {
    final payload = _prefs.getString(slot.key);
    return _HistoryEntryCodec.parse(payload, slotLabel: slot.label);
  }

  Future<void> _saveEntries(
    _HistoryStoreSlot slot,
    List<HistoryEntry> entries,
  ) async {
    final bounded = slot.mostRecent(entries);
    await _prefs.setString(slot.key, _HistoryEntryCodec.serialize(bounded));
  }
}

const _historySlot = _HistoryStoreSlot(
  key: HistoryStore._historyKey,
  label: 'history',
  maxEntries: HistoryStore.maxHistoryEntries,
);

const _favoritesSlot = _HistoryStoreSlot(
  key: HistoryStore._favoritesKey,
  label: 'favorites',
  maxEntries: HistoryStore.maxFavoriteEntries,
);

/// Storage contract for one SharedPreferences-backed history collection.
///
/// Entries are expected oldest-first. When a slot exceeds its cap, the oldest
/// entries are dropped and the most recent tail is retained.
class _HistoryStoreSlot {
  final String key;
  final String label;
  final int maxEntries;

  const _HistoryStoreSlot({
    required this.key,
    required this.label,
    required this.maxEntries,
  }) : assert(maxEntries > 0);

  List<HistoryEntry> mostRecent(List<HistoryEntry> entries) {
    if (entries.length <= maxEntries) return entries;
    return entries.sublist(entries.length - maxEntries);
  }
}

class _HistoryEntryCodec {
  const _HistoryEntryCodec._();

  static List<HistoryEntry> parse(String? payload,
      {required String slotLabel}) {
    if (payload == null || payload.isEmpty) return [];
    try {
      final decoded = jsonDecode(payload) as List;
      final entries = <HistoryEntry>[];
      for (final item in decoded) {
        try {
          final entry =
              HistoryEntry.fromJson((item as Map).cast<String, Object?>());
          entries.add(entry);
        } catch (e) {
          // Skip corrupted entry, continue with others.
          if (kDebugMode) {
            debugPrint('Failed to parse $slotLabel entry: $e');
          }
        }
      }
      return entries;
    } catch (e) {
      // Corrupted JSON, return empty list.
      if (kDebugMode) debugPrint('Failed to parse $slotLabel JSON: $e');
      return [];
    }
  }

  static String serialize(List<HistoryEntry> entries) {
    return jsonEncode(entries.map((e) => e.toJson()).toList());
  }
}

import 'package:shared_preferences/shared_preferences.dart';

/// Service to manage onboarding completion state.
///
/// Persists whether the user has completed the onboarding flow
/// using SharedPreferences.
class OnboardingService {
  static const String _onboardingCompleteKey = 'onboarding_complete';
  static const String _onboardingVersionKey = 'onboarding_version';

  /// Current onboarding version. Increment to show onboarding again
  /// after significant app updates.
  static const int currentVersion = 1;

  final SharedPreferences _prefs;

  OnboardingService._(this._prefs);

  /// Creates a new [OnboardingService] instance.
  static Future<OnboardingService> create() async {
    final prefs = await SharedPreferences.getInstance();
    return OnboardingService._(prefs);
  }

  /// Creates an [OnboardingService] with an existing [SharedPreferences] instance.
  factory OnboardingService.withPrefs(SharedPreferences prefs) {
    return OnboardingService._(prefs);
  }

  /// Returns true if onboarding has been completed for the current version.
  bool get isOnboardingComplete {
    final complete = _prefs.getBool(_onboardingCompleteKey) ?? false;
    final version = _prefs.getInt(_onboardingVersionKey) ?? 0;
    return complete && version >= currentVersion;
  }

  /// Marks onboarding as complete for the current version.
  Future<void> completeOnboarding() async {
    await _prefs.setBool(_onboardingCompleteKey, true);
    await _prefs.setInt(_onboardingVersionKey, currentVersion);
  }

  /// Resets onboarding state (useful for testing or user preference).
  Future<void> resetOnboarding() async {
    await _prefs.remove(_onboardingCompleteKey);
    await _prefs.remove(_onboardingVersionKey);
  }
}

import 'package:flutter/foundation.dart';
import 'package:shared_preferences/shared_preferences.dart';

/// User-facing renderer backend preference.
///
/// This setting lets users prefer CPU (stable) or GPU (fast) rendering.
///
/// - [RendererBackendMode.auto]: Use policy + health checks (recommended).
/// - [RendererBackendMode.cpuOnly]: Always use CPU renderer.
/// - [RendererBackendMode.gpuOnly]: Always try GPU renderer (debug).
///
/// Stored in SharedPreferences.
enum RendererBackendMode { auto, cpuOnly, gpuOnly }

class RendererSettingsService extends ChangeNotifier {
  static const String _keyBackendMode = 'renderer_backend_mode';

  final SharedPreferences _prefs;

  RendererBackendMode _backendMode;

  RendererSettingsService(this._prefs)
      : _backendMode = _decode(_prefs.getString(_keyBackendMode));

  static Future<RendererSettingsService> create() async {
    final prefs = await SharedPreferences.getInstance();
    return RendererSettingsService(prefs);
  }

  RendererBackendMode get backendMode => _backendMode;

  Future<void> setBackendMode(RendererBackendMode mode) async {
    if (_backendMode == mode) return;
    _backendMode = mode;
    await _prefs.setString(_keyBackendMode, mode.name);
    notifyListeners();
  }

  static RendererBackendMode _decode(String? raw) {
    switch (raw) {
      case 'cpuOnly':
        return RendererBackendMode.cpuOnly;
      case 'gpuOnly':
        return RendererBackendMode.gpuOnly;
      case 'auto':
      default:
        return RendererBackendMode.auto;
    }
  }
}

import 'package:flutter/material.dart';
import 'package:flutter/semantics.dart';
import 'package:shared_preferences/shared_preferences.dart';

/// Theme mode options for the app.
enum AppThemeMode {
  dark,
  oled,
  highContrast;

  String get displayName {
    switch (this) {
      case AppThemeMode.dark:
        return 'Dark';
      case AppThemeMode.oled:
        return 'OLED Black';
      case AppThemeMode.highContrast:
        return 'High Contrast';
    }
  }

  String get description {
    switch (this) {
      case AppThemeMode.dark:
        return 'Cosmic purple theme with dark gray background';
      case AppThemeMode.oled:
        return 'Pure black background for OLED displays';
      case AppThemeMode.highContrast:
        return 'Maximum contrast for accessibility';
    }
  }
}

/// Service for managing accessibility settings across the app.
///
/// Provides:
/// - High contrast mode for users with low vision
/// - Reduced motion mode for users with vestibular disorders
/// - Screen reader announcements helper
/// - Large text support detection
///
/// Settings are persisted to SharedPreferences and restored on app launch.
///
/// {@category Accessibility}
///
/// Example usage:
/// ```dart
/// final accessibility = AccessibilityService(prefs);
///
/// // Check if high contrast mode is enabled
/// if (accessibility.highContrastEnabled) {
///   // Use high contrast colors
/// }
///
/// // Announce to screen readers
/// accessibility.announce('Fractal loaded');
/// ```
class AccessibilityService extends ChangeNotifier {
  static const String _keyHighContrast = 'accessibility_high_contrast';
  static const String _keyReducedMotion = 'accessibility_reduced_motion';
  static const String _keyLargeTargets = 'accessibility_large_targets';
  static const String _keyThemeMode = 'app_theme_mode';

  final SharedPreferences _prefs;

  bool _highContrastEnabled;
  bool _reducedMotionEnabled;
  bool _largeTargetsEnabled;
  AppThemeMode _themeMode;

  /// Creates an [AccessibilityService] with the given [SharedPreferences].
  AccessibilityService(this._prefs)
      : _highContrastEnabled = _prefs.getBool(_keyHighContrast) ?? false,
        _reducedMotionEnabled = _prefs.getBool(_keyReducedMotion) ?? false,
        _largeTargetsEnabled = _prefs.getBool(_keyLargeTargets) ?? false,
        _themeMode = AppThemeMode.values[(_prefs.getInt(_keyThemeMode) ?? 0)
            .clamp(0, AppThemeMode.values.length - 1)];

  /// Creates an instance asynchronously by loading SharedPreferences.
  static Future<AccessibilityService> create() async {
    final prefs = await SharedPreferences.getInstance();
    return AccessibilityService(prefs);
  }

  /// Whether high contrast mode is enabled.
  ///
  /// When true, the app should use higher contrast colors
  /// with more distinct borders and larger text.
  bool get highContrastEnabled => _highContrastEnabled;

  /// Whether reduced motion mode is enabled.
  ///
  /// When true, animations should be minimized or disabled
  /// to help users with vestibular disorders.
  bool get reducedMotionEnabled => _reducedMotionEnabled;

  /// Whether large touch targets are enabled.
  ///
  /// When true, interactive elements should have larger hit areas
  /// (minimum 48x48 logical pixels per WCAG guidelines).
  bool get largeTargetsEnabled => _largeTargetsEnabled;

  /// The current app theme mode.
  AppThemeMode get themeMode => _themeMode;

  /// Enables or disables high contrast mode.
  Future<void> setHighContrast(bool enabled) async {
    if (_highContrastEnabled == enabled) return;
    _highContrastEnabled = enabled;
    await _prefs.setBool(_keyHighContrast, enabled);
    notifyListeners();
  }

  /// Enables or disables reduced motion mode.
  Future<void> setReducedMotion(bool enabled) async {
    if (_reducedMotionEnabled == enabled) return;
    _reducedMotionEnabled = enabled;
    await _prefs.setBool(_keyReducedMotion, enabled);
    notifyListeners();
  }

  /// Enables or disables large touch targets.
  Future<void> setLargeTargets(bool enabled) async {
    if (_largeTargetsEnabled == enabled) return;
    _largeTargetsEnabled = enabled;
    await _prefs.setBool(_keyLargeTargets, enabled);
    notifyListeners();
  }

  /// Sets the app theme mode.
  Future<void> setThemeMode(AppThemeMode mode) async {
    if (_themeMode == mode) return;
    _themeMode = mode;
    await _prefs.setInt(_keyThemeMode, mode.index);
    notifyListeners();
  }

  /// Announces a message to screen readers.
  ///
  /// Uses [SemanticsService] to make the message
  /// audible to TalkBack/VoiceOver users.
  ///
  /// [politeness] controls interruption behavior:
  /// - [Assertiveness.polite]: Waits for current speech to finish
  /// - [Assertiveness.assertive]: Interrupts current speech (use sparingly)
  static void announce(
    String message, {
    Assertiveness politeness = Assertiveness.polite,
  }) {
    // ignore: deprecated_member_use
    SemanticsService.announce(message, TextDirection.ltr,
        assertiveness: politeness);
  }

  /// Checks if the system has accessibility features enabled.
  ///
  /// Returns true if any of these are active:
  /// - Screen reader (TalkBack/VoiceOver)
  /// - Reduce motion preference
  /// - Bold text preference
  /// - High contrast preference
  static bool isSystemAccessibilityEnabled(BuildContext context) {
    final mediaQuery = MediaQuery.of(context);
    return mediaQuery.accessibleNavigation ||
        mediaQuery.disableAnimations ||
        mediaQuery.boldText ||
        mediaQuery.highContrast;
  }

  /// Checks if the system prefers reduced motion.
  ///
  /// This checks the OS-level "Reduce Motion" setting.
  static bool systemPrefersReducedMotion(BuildContext context) {
    return MediaQuery.of(context).disableAnimations;
  }

  /// Checks if a screen reader is active.
  ///
  /// Returns true when TalkBack (Android) or VoiceOver (iOS) is running.
  static bool isScreenReaderActive(BuildContext context) {
    return MediaQuery.of(context).accessibleNavigation;
  }

  /// Returns the appropriate animation duration based on settings.
  ///
  /// If reduced motion is enabled (either in-app or system-level),
  /// returns [Duration.zero] to disable animations.
  Duration getAnimationDuration(BuildContext context, Duration normalDuration) {
    if (_reducedMotionEnabled || systemPrefersReducedMotion(context)) {
      return Duration.zero;
    }
    return normalDuration;
  }
}

/// Extension to check accessibility preferences from BuildContext.
extension AccessibilityContext on BuildContext {
  /// Whether animations should be reduced based on user/system preferences.
  bool get shouldReduceMotion {
    return MediaQuery.of(this).disableAnimations;
  }

  /// Whether a screen reader is currently active.
  bool get isScreenReaderActive {
    return MediaQuery.of(this).accessibleNavigation;
  }

  /// Whether the system prefers high contrast.
  bool get prefersHighContrast {
    return MediaQuery.of(this).highContrast;
  }

  /// Whether bold text is enabled system-wide.
  bool get prefersBoldText {
    return MediaQuery.of(this).boldText;
  }
}

import 'dart:io';

import 'package:flutter/foundation.dart';
import 'package:flutter/services.dart';
/// Wallpaper destination supported by platform wallpaper APIs.
enum WallpaperTarget { home, lock, both }

/// Sets the generated fractal as the device wallpaper.
///
/// Platform notes:
/// - Android: uses [android.app.WallpaperManager] to set HOME/LOCK/BOTH.
/// - iOS: iOS does not allow setting wallpaper programmatically. We save the
///   image to Photos instead (so the user can set it from the Photos app).
class WallpaperService {
  static const MethodChannel _channel =
      MethodChannel('com.fractalforge/wallpaper');

  const WallpaperService();

  Future<bool> setWallpaper(
    Uint8List pngBytes, {
    required WallpaperTarget target,
  }) async {
    if (kIsWeb) {
      throw UnsupportedError('Wallpaper setting is not supported on web.');
    }

    if (Platform.isIOS) {
      // iOS does not allow programmatic wallpaper setting. Save to Photos.
      return saveToPhotos(pngBytes);
    }

    final ok = await _channel.invokeMethod<bool>('setWallpaper', {
      'bytes': pngBytes,
      'target': target.name,
    });

    return ok ?? false;
  }

  Future<bool> saveToPhotos(Uint8List pngBytes) async {
    if (kIsWeb) {
      throw UnsupportedError('Saving to Photos is not supported on web.');
    }

    final ok = await _channel.invokeMethod<bool>('saveToPhotos', {
      'bytes': pngBytes,
    });

    return ok ?? false;
  }
}

